import itertools, math, numpy as np
from scipy.optimize import differential_evolution, minimize

def prob_success(w,p):
    n=len(w)
    prob=0.0
    for mask in range(1<<n):
        s=0; k=0
        for i in range(n):
            if mask>>i &1:
                s += w[i]; k+=1
        if s >= p-1e-12:
            prob += (p**k)*((1-p)**(n-k))
    return prob

def min_for_n(n,p,tries=20):
    # param softmax? use n-1 simplex
    def obj(x):
        # x length n-1, last=1-sum if feasible
        if np.any(x<0) or x.sum()>1: return 10+(x.sum()-1)**2
        w=np.r_[x,1-x.sum()]
        return prob_success(w,p)
    bounds=[(0,1)]*(n-1)
    cons=({'type':'ineq','fun':lambda x: 1-np.sum(x)})
    best=(10,None)
    for _ in range(tries):
        x0=np.random.dirichlet(np.ones(n))[:-1]
        res=minimize(obj,x0,bounds=bounds,constraints=cons,method='SLSQP',options={'maxiter':1000,'ftol':1e-12})
        if res.fun<best[0]-1e-9:
            best=(res.fun,np.r_[res.x,1-res.x.sum()])
    return best

for p in [0.1,0.2,0.3,1/3]:
    print('p',p)
    for n in range(2,8):
        best=min_for_n(n,p,tries=50)
        print(n,best[0],np.round(best[1],4))
    print()

def min_for_n_cap(n,p,cap,tries=50):
    def obj(x):
        if np.any(x<0) or x.sum()>1: return 10
        w=np.r_[x,1-x.sum()]
        if np.max(w)>cap+1e-9: return 10+100*(np.max(w)-cap)**2
        return prob_success(w,p)
    bounds=[(0,cap)]*(n-1)
    cons=({'type':'ineq','fun':lambda x: 1-np.sum(x)},
          {'type':'ineq','fun':lambda x: cap-(1-np.sum(x))})
    best=(10,None)
    for _ in range(tries):
        # random simplex with cap
        while True:
            w=np.random.dirichlet(np.ones(n))
            if np.max(w)<=cap: break
        res=minimize(obj,w[:-1],bounds=bounds,constraints=cons,method='SLSQP',options={'maxiter':1000,'ftol':1e-12})
        if res.fun<best[0]-1e-9:
            best=(res.fun,np.r_[res.x,1-res.x.sum()])
    return best

