def phi_q(w,q):
    n=len(w); prob=0
    for mask in range(1<<n):
        s=0;k=0
        for i in range(n):
            if mask>>i&1:
                s+=w[i]; k+=1
        if s>q+1e-12:
            prob += q**k*(1-q)**(n-k)
    return prob
def check_monotone(w):
    qs=np.linspace(0.001,0.999,999)
    vals=np.array([phi_q(w,q)/q for q in qs])
    return np.max(np.diff(vals)), qs[np.argmax(np.diff(vals))], vals[np.argmax(np.diff(vals))], vals[np.argmax(np.diff(vals))+1]
for n in range(2,8):
    maxdiff=-1; bad=None
    for _ in range(1000):
        w=np.random.dirichlet(np.ones(n))
        d=check_monotone(w)
        if d[0]>maxdiff:
            maxdiff=d[0]; bad=(w,d)
    print(n,maxdiff,bad[1],np.round(bad[0],3))

def check_monotone_range(w,a=2/3,b=.999):
    qs=np.linspace(a,b,500)
    vals=np.array([phi_q(w,q)/q for q in qs])
    dif=np.diff(vals)
    return np.max(dif), qs[np.argmax(dif)], vals[np.argmax(dif)], vals[np.argmax(dif)+1]
